import React from 'react'
import { useNavigate } from 'react-router-dom'
import { API } from '../../api'

const th = { border: '1px solid #ccc', padding: 10, textAlign: 'left' }
const td = { border: '1px solid #eee', padding: 10 }

const Kassa = () => {
  const [cart, setCart]         = React.useState([])
  const [goods, setGoods]       = React.useState([])
  const [payment, setPayment]   = React.useState('cash')
  const inputRef                = React.useRef()
  const navigate                = useNavigate()

  const total = cart.reduce((s, i) => s + i.qty * +i.price, 0)

  /* ---------- загрузка ассортимента ---------- */
  React.useEffect(() => {
    API.getStocks()
      .then(r => setGoods(r.data))
      .catch(e => console.error('Ошибка загрузки товаров', e))
  }, [])

  /* ---------- сканирование ---------- */
  const handleScan = e => {
    if (e.key !== 'Enter') return
    const code = e.target.value.trim()
    if (!code) return

    const item = goods.find(g => g.code === code)
    if (!item) { alert('Товар не найден'); e.target.value = ''; return }

    setCart(prev => {
      const ex = prev.find(p => p.id === item.id)
      return ex
        ? prev.map(p => p.id === item.id ? { ...p, qty: p.qty + 1 } : p)
        : [...prev, { ...item, qty: 1 }]
    })
    e.target.value = ''
  }

  /* ---------- изменение количества ---------- */
  const changeQty = (idx, delta) => {
    setCart(prev =>
      prev.map((row, i) =>
        i === idx ? { ...row, qty: Math.max(1, row.qty + delta) } : row
      )
    )
  }

  const setQtyManually = (idx, value) => {
    const n = Math.max(1, parseInt(value) || 1)
    setCart(prev => prev.map((r, i) => i === idx ? { ...r, qty: n } : r))
  }

  /* ---------- продажа ---------- */
  const handleSell = async () => {
    if (!cart.length) return alert('Корзина пуста')
    try {
      const payload = {
        total: total.toFixed(2),
        payment_type: payment,
        items: cart.map(i => ({
          code: i.code, name: i.name, price: +i.price,
          quantity: i.qty, total: (+i.price * i.qty).toFixed(2)
        }))
      }
      const res = await API.createSale(payload)
      localStorage.setItem('receipt', JSON.stringify(res.data))
      setCart([])
      navigate('/receipt')
    } catch (e) {
      console.error('Ошибка при продаже', e); alert('Ошибка при продаже')
    }
  }

  /* ---------- UI ---------- */
  return (
    <div style={{ padding: 24, maxWidth: 800, margin: '0 auto', fontFamily: 'sans-serif' }}>
      <h2>🧾 Касса</h2>

      <input
        ref={inputRef} autoFocus
        placeholder="Сканируйте штрихкод…"
        onKeyDown={handleScan}
        style={{ width: '100%', padding: 12, fontSize: 16, marginBottom: 20 }}
      />

      <div style={{ marginBottom: 20 }}>
        <label>Тип оплаты: </label>
        <select value={payment} onChange={e => setPayment(e.target.value)} style={{ padding: 6, marginLeft: 8 }}>
          <option value="cash">Наличные</option>
          <option value="card">Карта</option>
        </select>
      </div>

      <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 20 }}>
        <thead style={{ background: '#f0f0f0' }}>
          <tr><th style={th}>Название</th><th style={th}>Цена</th><th style={th}>Кол-во</th><th style={th}>Сумма</th></tr>
        </thead>
        <tbody>
          {cart.map((it, idx) => (
            <tr key={idx}>
              <td style={td}>{it.name}</td>
              <td style={td}>{(+it.price).toFixed(2)} сом</td>

              {/* --- Кол-во с +/- и вводом --- */}
              <td style={td}>
                <button onClick={() => changeQty(idx, -1)} style={btn}>−</button>
                <input
                  type="number" min={1}
                  value={it.qty}
                  onChange={e => setQtyManually(idx, e.target.value)}
                  style={{ width: 50, textAlign: 'center' }}
                />
                <button onClick={() => changeQty(idx, +1)} style={btn}>+</button>

                <p>Остаток: {it.quantity-it.qty}</p>
              </td>

              <td style={td}>{(it.qty * +it.price).toFixed(2)} сом</td>
            </tr>
          ))}
        </tbody>
      </table>

      <h3 style={{ textAlign: 'right' }}>Итого: {total.toFixed(2)} сом</h3>

      <div style={{ textAlign: 'right' }}>
        <button onClick={handleSell} style={{
          background: '#27ae60', color: '#fff', padding: '10px 20px',
          fontSize: 16, border: 'none', cursor: 'pointer'
        }}>
          ✅ Продать
        </button>
      </div>
    </div>
  )
}

const btn = {
  width: 28, height: 28, margin: '0 4px',
  border: '1px solid #ccc', background: '#fff', cursor: 'pointer'
}

export default Kassa
